queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?chefs a :Chefs .
    ?chefs p:name ?name .
    ?chefs p:language ?language_f .
    FILTER(STR(?language_f) = "Spanish")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?servers a :Servers .
    ?servers p:name ?name .
    ?servers p:language ?language_f .
    FILTER(STR(?language_f) = "Spanish")
    BIND(?name AS ?o0)
  }
}

